function computeExpression(expr) {
  expr = String(expr).replace(/\s+/g, '');
  if (!/^[\d.+\-*/()]+$/.test(expr)) throw new Error('Invalid expression');
  let i = 0;

  function parseExpression() {
    let value = parseTerm();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '+' && op !== '-') break;
      i++;
      const next = parseTerm();
      value = op === '+' ? value + next : value - next;
    }
    return value;
  }

  function parseTerm() {
    let value = parseFactor();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '*' && op !== '/') break;
      i++;
      const next = parseFactor();
      value = op === '*' ? value * next : value / next;
    }
    return value;
  }

  function parseFactor() {
    if (expr[i] === '+') return i++, parseFactor();
    if (expr[i] === '-') return i++, -parseFactor();
    if (expr[i] === '(') {
      i++;
      const value = parseExpression();
      if (expr[i] !== ')') throw new Error('Mismatched parentheses');
      i++;
      return value;
    }
    const start = i;
    while (i < expr.length && /[\d.]/.test(expr[i])) i++;
    if (start === i) throw new Error('Invalid number');
    return parseFloat(expr.slice(start, i));
  }

  const result = parseExpression();
  if (i !== expr.length || !Number.isFinite(result)) throw new Error('Invalid expression');
  return result;
}
